pragma solidity ^0.8.10;
import {FlashLoanSimpleReceiverBase} from '@aave/core-v3/contracts/flashloan/base/FlashLoanSimpleReceiverBase.sol';
import {IPoolAddressesProvider} from '@aave/core-v3/contracts/interfaces/IPoolAddressesProvider.sol';
import {IERC20} from '@aave/core-v3/contracts/dependencies/openzeppelin/contracts/IERC20.sol';
contract MyFlashLoan is FlashLoanSimpleReceiverBase {
  constructor(address provider) FlashLoanSimpleReceiverBase(IPoolAddressesProvider(provider)) {}
  function executeOperation(address asset, uint256 amount, uint256 premium, address initiator, bytes calldata params) external override returns (bool) {
    // YOUR LOGIC HERE
    uint256 amountOwed = amount + premium;
    IERC20(asset).approve(address(POOL), amountOwed);
    return true;
  }
  function requestFlashLoan(address token, uint256 amount) public {
    POOL.flashLoanSimple(address(this), token, amount, '', 0);
  }
}
